# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import os
import getpass
import mysql.connector

def escape_path(path):
    return path.replace("\\", "\\\\").replace("'", "\\'")

def get_connection():
    host = input("MySQL host [localhost]: ") or "localhost"
    user = input("User [root]: ") or "root"
    password = getpass.getpass("Password: ")
    database = input("Database: ")
    return mysql.connector.connect(
        host=host,
        user=user,
        password=password,
        database=database,
        allow_local_infile=True
    )

def enable_local_infile(cursor):
    try:
        cursor.execute("SET GLOBAL local_infile = 1")
    except mysql.connector.Error:
        pass  # Requires SUPER; ignore if not permitted
    cursor.execute("SET SESSION local_infile = 1")

def build_load_sql(path, table):
    return (
        "LOAD DATA LOCAL INFILE '{path}' "
        "INTO TABLE `{table}` "
        "FIELDS TERMINATED BY ',' "
        "ENCLOSED BY '\"' "
        "LINES TERMINATED BY '\\n' "
        "IGNORE 1 LINES"
    ).format(path=escape_path(path), table=table)

def main():
    cnx = get_connection()
    cur = cnx.cursor()
    enable_local_infile(cur)

    while True:
        file_path = input("Enter file path to load (or 'q' to quit): ").strip()
        if file_path.lower() == "q":
            break
        if not os.path.isfile(file_path):
            print("File not found.")
            continue

        table = input("Target table [leave blank to use file name]: ").strip()
        if not table:
            table = os.path.splitext(os.path.basename(file_path))[0]

        sql = build_load_sql(file_path, table)
        try:
            cur.execute(sql)
            cnx.commit()
            print(f"Loaded {cur.rowcount} rows into '{table}'.")
        except mysql.connector.Error as err:
            print(f"Error: {err}")
            cnx.rollback()

    cur.close()
    cnx.close()

if __name__ == "__main__":
    main()